FROM TWORK_INFO_IVAT A INNER JOIN TWORK_INFO_IVATXLCXULC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY AND A.IVATKEY = B.IVATKEY INNER JOIN TWORK_MST_IC C ON A.OWKEY = C.OWKEY AND A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY INNER JOIN TWORK_MST_LC D ON B.CTKEY = D.CTKEY AND B.LCKEY = D.LCKEY INNER JOIN TADMIN_MST_ICXCT E ON C.OWKEY = E.OWKEY AND C.ICKEY = E.ICKEY AND C.CTKEY = E.CTKEY INNER JOIN TADMIN_MST_OW F ON C.OWKEY = F.OWKEY WHERE B.TTQTY > 0 AND EXISTS (SELECT 1 FROM TWORK_MST_CT X WHERE A.CTKEY = X.CTKEY) AND D.LCHOLDTYPE IN ('20','30') AND A.ATTRIBUTE2 = #{attribute} AND F.OWKEY = #{owkey}
AND F.OWKEY IN
#{OWKEY_SELECTION_VALUE}
AND ICKEY = #{value}
AND (C.ICKEY LIKE '%' || #{value} || '%' OR C.ICNAME LIKE '%' || #{value} || '%' OR F.OWKEY LIKE '%' || #{value} || '%')
GROUP BY F.OWNAME, A.ICKEY, C.ICKEY, C.ICNAME, A.ATTRIBUTE3, A.PRODUCTLOT

