mapper.select:
SELECT * FROM ( SELECT A.* , ROW_NUMBER() OVER() AS PAGING_NUM FROM ( SELECT B.* FROM( SELECT ORDERCOMDTKEY AS FIELD1 , ORDERCOMDTNM AS FIELD2 , ORDERCOMDTVAL AS FIELD3, ORDERCOMHDKEY AS FIELD4, DTKEYORD AS DTKEYORD
) AS B
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY DTKEYORD ASC
) AS A ) AS paging_wrap
WHERE PAGING_NUM > (#{currentPage} -1)* #{pagingLimit} AND PAGING_NUM <= #{currentPage} * #{pagingLimit}

SELECT * FROM ( SELECT A.* , ROW_NUMBER() OVER() AS PAGING_NUM FROM ( SELECT B.* FROM( SELECT ADCDDTKEY AS FIELD1 , ADCDDTNM AS FIELD2 , ADCDDTVALUE AS FIELD3, ADCDHDKEY AS FIELD4, ADCDDTORDER AS DTKEYORD
) AS B
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY ADCDDTORDER ASC
) AS A ) AS paging_wrap
WHERE PAGING_NUM > (#{currentPage} -1)* #{pagingLimit} AND PAGING_NUM <= #{currentPage} * #{pagingLimit}

