FROM TORDER_MST_AC
WHERE 1 = 1

	AND ACTYPE = #{actype}


	AND OWKEY = #{owkey}


	AND OWKEY IN

		#{owList}



	AND (ACKEY LIKE '%' || #{value} || '%' OR ACNM LIKE '%'|| #{value} || '%' )

FROM TADMIN_MST_OW A

	AND EXISTS (
		SELECT 1
		FROM T_ROLE_OW
		WHERE OWKEY = A.OWKEY
	)
	AND A.DELYN = 'N'



				AND A.OWKEY = #{value}


				AND (
				A.OWKEY ~ #{value}
				OR
				A.OWNM ~ #{value}
				)


				AND (
				A.OWKEY LIKE '%' || #{value} || '%'
				OR
				A.OWNM LIKE '%' || #{value} || '%'
				)

FROM TORDER_MST_CT A -- 센터코드 INNER JOIN TORDER_MST_CTXOW B ON A.CTKEY = B.CTKEY LEFT OUTER JOIN TORDER_MST_COM_DT C ON C.COMHDKEY ='CTTYPE' AND A.CTTYPE = C.COMDTKEY AND C.LAKEY = #{lakey} WHERE A.CLOSDATE >= #{sysdate} AND A.DELYN = 'N' --AND A.MANAGEMENTYN = 'Y' AND B.OWKEY = #{owkey}
AND A.CTKEY IN
#{CTKEY_SELECTION_VALUE}
AND (A.CTKEY LIKE '%'|| #{value} || '%' OR A.CTNM LIKE '%'|| #{value} || '%' OR A.CTTYPE LIKE '%'|| #{value} || '%' OR A.CNTRYCD LIKE '%'|| #{value} || '%' OR A.CLOSDATE LIKE '%'|| #{value} || '%')
AND (A.CTKEY LIKE '%'|| #{popParam} || '%' OR A.CTNM LIKE '%'|| #{popParam} || '%')
AND A.CTTYPE = '02'

/* oms-common-sql-oracle.xml - sql_tadminMstIcgr */
	FROM TORDER_MST_ICGR

		CLOSDATE >= #{sysdate}

			AND OWKEY = #{owkey}


			AND OWKEY IN

				#{owList}



			AND (ICGRPKEY LIKE '%' || #{value} || '%' OR ICGRPNM LIKE '%' || #{value} || '%' OR  OWKEY LIKE '%' || #{value} || '%' )

FROM TORDER_MST_IC A
INNER JOIN TORDER_MST_ICUTXTYPE B
		ON A.OWKEY = B.OWKEY
	   --AND A.ICUNITKEY = B.ICUTKEY // 추후제거 및 컬럼변경
	WHERE A.CLOSDATE >= #{sysdate}

	AND A.ICUNITKEY = #{icutkey}


	AND A.OWKEY = #{owkey}


	AND (A.ICUNITKEY LIKE '%'|| #{value} || '%' OR A.CLOSDATE LIKE '%'|| #{value} || '%')


	AND A.OWKEY IN

		#{owList}

FROM TORDER_MST_IC A INNER JOIN TORDER_MST_ICUTXTYPE B ON A.ICKEY = B.ICKEY AND A.OWKEY = B.OWKEY AND A.UOM = B.ICUNITTYPE
INNER JOIN ( SELECT OWKEY, ICKEY FROM (
SELECT COALESCE(#{owkey}, #{sowkey}) AS OWKEY , #{item} AS ICKEY
) T GROUP BY OWKEY, ICKEY ) T_SCH ON A.OWKEY = T_SCH.OWKEY AND A.ICKEY LIKE T_SCH.ICKEY || '%'
AND A.OWKEY IN
#{owkey}
AND A.CLOSDATE >= #{sysdate} AND A.DELYN = 'N'
AND A.OWKEY = #{owkey}
AND A.ICKEY = #{value}
AND ( A.ICKEY LIKE '%' || #{value} || '%' OR A.ICNM LIKE '%' || #{value} || '%' )

FROM TADMIN_MST_IC A INNER JOIN TADMIN_MST_ICXCT B ON A.ICKEY = B.ICKEY LEFT OUTER JOIN TWORK_INFO_IVAT C ON A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY AND B.CTKEY = C.CTKEY LEFT OUTER JOIN TWORK_INFO_IVATXLCXULC D ON C.CTKEY = D.CTKEY AND C.OWKEY = D.OWKEY AND C.ICKEY = D.ICKEY AND C.IVATKEY = D.IVATKEY WHERE A.CLOSDATE >= #{sysdate} AND A.DELYN = 'N'
AND A.OWKEY IN
#{OWKEY_SELECTION_VALUE}
AND A.OWKEY = #{owkey}
AND A.ACKEY = #{ackey}
AND B.CTKEY = #{ctkey}
AND (A.ICKEY LIKE '%'|| #{value} || '%' OR A.ICNM LIKE '%'|| #{value} || '%' OR A.ICUNITKEY LIKE '%'|| #{value} || '%' OR A.UOM LIKE '%'|| #{value} || '%' )
GROUP BY A.ICKEY, A.ICNAME, A.OWKEY, A.ICUTKEY, A.UOM, B.LOGGRPCD

FROM TADMIN_MST_ICSB
WHERE
CLOSDATE >= #{sysdate}

	AND OWKEY IN

		#{OWKEY_SELECTION_VALUE}



	AND (ICKEY LIKE '%' || #{value} || '%' OR SBKEY LIKE '%' || #{value} || '%' OR OWKEY LIKE '%' || #{value} || '%' OR ICUNITTYPE LIKE '%' || #{value} || '%')

FROM TORDER_MST_ZC
WHERE
COUNTRYCODE = #{countrycode}

	AND DLCOMPANY = #{dlcompany}


	AND      (  ZIP_NO LIKE '%'|| #{value} || '%'
	OR SIDO_ADDR LIKE '%'|| #{value} || '%'
	OR SKK_ADDR LIKE '%'|| #{value} || '%'
	OR DONG_ADDR LIKE '%'|| #{value} || '%'
	OR DLCOMPANY LIKE '%'|| #{value} || '%'
	)

FROM TADMIN_MST_ICUTXTYPE


		ICUNITKEY = #{icutkey}


		(ICUNITKEY LIKE '%'|| #{value} || '%' OR ICUNITTYPE LIKE '%'|| #{value} || '%')

FROM 	TORDER_MST_ICMP_HD
WHERE 	1=1

	AND	(
	ICMPKEY LIKE '%'|| #{value} || '%'
	OR OWKEY LIKE '%'|| #{value} || '%'
	)


	AND	 	OWKEY IN

		#{OWKEY_AUTH_LIST}



	AND 	OWKEY = #{owkey}

FROM TADMIN_MST_SEIC_HD A INNER JOIN TADMIN_MST_IC B ON B.OWKEY = A.OWKEY AND B.ICKEY = A.ICKEY WHERE A.CLOSDATE >= #{sysdate}
AND (A.SETICKEY LIKE '%' || #{value} || '%' OR A.ICKEY LIKE '%'|| #{value} || '%' OR A.ICUNITKEY LIKE '%'|| #{value} || '%' OR B.ICNM LIKE '%'|| #{value} || '%')
AND A.OWKEY IN
#{OWKEY_AUTH_LIST}

FROM TADMIN_MST_ICXCT A
INNER JOIN TADMIN_MST_IC B
		ON A.OWKEY = B.OWKEY
	   AND A.ICKEY = B.ICKEY
INNER JOIN TADMIN_MST_CT C
		ON A.CTKEY = C.CTKEY
WHERE B.CLOSDATE >= #{sysdate}
AND B.DELYN = 'N'

	AND A.OWKEY = #{owkey}


	AND A.CTKEY = #{ctkey}


	AND A.ICKEY = #{ickey}


	AND A.ACKEY = #{ackey}


	AND A.OWKEY IN

		#{OWKEY_AUTH_LIST}



	AND (A.OWKEY LIKE '%'|| #{value} || '%'
	OR A.ICKEY LIKE '%'|| #{value} || '%'
	OR B.ICNM LIKE '%'|| #{value} || '%'
	OR B.ICUNITKEY LIKE '%'|| #{value} || '%'
	OR B.UOM LIKE '%'|| #{value} || '%'
	OR C.CTNM LIKE '%'|| #{value} || '%'
	)

FROM TADMIN_MST_STOREXCT A INNER JOIN TADMIN_MST_STORE B ON A.STOREKEY = B.STOREKEY WHERE B.CLOSDATE >= #{sysdate} AND B.DELYN = 'N'
AND A.CTKEY = #{ctkey}
AND (A.STOREKEY LIKE '%' || #{value} || '%' OR B.STORENM LIKE '%'|| #{value} || '%' )
AND B.OWKEY IN
#{OWKEY_SELECTION_VALUE}
GROUP BY A.STOREKEY ,B.STORENM, A.CTKEY

