mapper.sql:
FROM TORDER_MST_IC IC

	AND IC.DELYN = 'N'

		AND IC.OWKEY = #{owkey}








		AND IC.ICKEY = #{ickey}




				AND IC.ICKEY = #{value}


				AND (
				IC.ICKEY ~ #{value}
				OR
				IC.ICNM ~ #{value}
				)


				AND (
				IC.ICKEY LIKE '%' || #{value} || '%'
				OR
				IC.ICNM LIKE '%' || #{value} || '%'
				)

FROM TORDER_MST_IC IC
LEFT JOIN TORDER_MST_ASRT A
   ON IC.OWKEY = A.OWKEY
  AND IC.ICKEY = A.ASRTKEY
  LEFT JOIN TORDER_MST_AC AC
  	ON AC.OWKEY = IC.OWKEY
   AND AC.ACKEY = IC.ACKEY
   AND AC.DELYN  <>  'Y'

	AND IC.DELYN = 'N'
	AND NOT EXISTS( SELECT 1 FROM  TORDER_MST_ASRT  C
	WHERE  C.ASRTREPKEY  = IC.ICKEY )

		AND IC.OWKEY = #{owkey}


		AND A.ASRTREPKEY = #{ickey}


		AND IC.ACKEY = #{ackey}


		AND IC.ASRTKEY = #{asrtkey}




				AND IC.ICKEY = #{value}


				AND (
				IC.ICKEY ~ #{value}
				OR
				IC.ICNM ~ #{value}
				)


				AND (
				IC.ICKEY LIKE '%' || #{value} || '%'
				OR
				IC.ICNM LIKE '%' || #{value} || '%'
				)

FROM TORDER_MST_IC IC INNER JOIN TORDER_MST_IC_ORG ORG ON IC.OWKEY = ORG.OWKEY AND IC.ICKEY = ORG.ICKEY INNER JOIN TORDER_MST_ICUTXTYPE EA ON EA.OWKEY = IC.OWKEY AND EA.ICKEY = IC.ICKEY AND EA.ICUNITTYPE = IC.UOM AND EA.ICUNITTYPE = 'EA' LEFT JOIN TORDER_MST_ICUTXTYPE INN ON INN.OWKEY = IC.OWKEY AND INN.ICKEY = IC.ICKEY AND INN.ICUNITTYPE = 'INN' LEFT JOIN TORDER_MST_ICUTXTYPE CTN ON CTN.OWKEY = IC.OWKEY AND CTN.ICKEY = IC.ICKEY AND CTN.ICUNITTYPE = 'CTN' LEFT JOIN TORDER_MST_AC AC ON AC.OWKEY = IC.OWKEY AND AC.ACKEY = IC.ACKEY AND AC.DELYN <> 'Y' LEFT JOIN TORDER_MST_ASRT ASRT ON IC.OWKEY = ASRT.OWKEY AND IC.ICKEY = ASRT.ASRTREPKEY LEFT JOIN TORDER_MST_IC REP ON ASRT.OWKEY = REP.OWKEY AND ASRT.ASRTKEY = REP.ICKEY
AND IC.DELYN = 'N'
AND IC.OWKEY = #{owkey}
AND IC.ICKEY = #{ickey}
AND ( ASRT.ASRTKEY = #{olnickey} OR ORG.ICKEY = #{olnickey} )
AND IC.ACKEY = #{ackey}
AND IC.ICKEY = #{value}
AND ( ASRT.ASRTKEY ~ #{value} OR ASRT.ASRTNM ~ #{value} )
AND ( ASRT.ASRTKEY LIKE '%' || #{value} || '%' OR ASRT.ASRTNM LIKE '%' || #{value} || '%' )

mapper.select:
/* oms-common-sql-oracle.xml - selectTOrderMstOrderTypeList */ SELECT ORDERTYPECD AS FIELD1 , ORDERTYPECD || ' : '|| ORDERTYPENM AS FIELD2 , IBYN AS FIELD3 , OBYN AS FIELD4 , ORDERAT AS FIELD5 , OWKEY AS FIELD6 , ORDERTYPECD || ' : '|| ORDERTYPECD AS FIELD7 FROM TORDER_MST_ORTYPE WHERE DELYN = 'N'
AND IBYN = #{ibyn}
AND OBYN = #{obyn}
AND ORDERAT = #{orderAttr}
ORDER BY LPAD(ORDERTYPECD::TEXT, 20, '0')

/* oms-common-sql-oracle.xml - selectTOrderMstOwOrderTypeGList */ SELECT TB.FIELD1 , TB.FIELD2 , TB.FIELD5 FROM ( SELECT A.EXTORDERTYPECD AS FIELD1 , A.EXTORDERTYPECD || ' : ' || B.EXTORDERTYPENM AS FIELD2 , A.ORDERTYPECD || ' : '|| C.ORDERTYPENM AS FIELD3 , A.ORDERTYPECD AS FIELD4 , A.OWKEY AS FIELD5 , C.ORDERTYPENM AS FIELD6 , B.EXTORDERTYPENM AS FIELD7 FROM TORDER_INFO_ORTYPE_MAPPING A INNER JOIN TORDER_MST_EXTERN B ON A.OWKEY = B.OWKEY AND A.EXTORDERTYPECD = B.EXTORDERTYPECD AND B.DELYN = 'N' INNER JOIN TORDER_MST_ORTYPE C ON A.OWKEY = C.OWKEY AND A.ORDERTYPECD = C.ORDERTYPECD AND C.DELYN = 'N' WHERE A.DELYN = 'N'
AND A.OWKEY = #{owkey}
AND A.OWKEY IN
#{owList}
ORDER BY A.EXTORDERTYPECD ) TB GROUP BY TB.FIELD1, TB.FIELD2, TB.FIELD5 ORDER BY TB.FIELD1

mapper.sql:
FROM TORDER_MST_IC IC INNER JOIN TORDER_MST_IC_ORG ORG ON IC.OWKEY = ORG.OWKEY AND IC.ICKEY = ORG.ICKEY INNER JOIN TORDER_MST_ICUTXTYPE EA ON EA.OWKEY = IC.OWKEY AND EA.ICKEY = IC.ICKEY AND EA.ICUNITTYPE = IC.UOM AND EA.ICUNITTYPE = 'EA' LEFT JOIN TORDER_MST_ICUTXTYPE INN ON INN.OWKEY = IC.OWKEY AND INN.ICKEY = IC.ICKEY AND INN.ICUNITTYPE = 'INN' LEFT JOIN TORDER_MST_ICUTXTYPE CTN ON CTN.OWKEY = IC.OWKEY AND CTN.ICKEY = IC.ICKEY AND CTN.ICUNITTYPE = 'CTN' LEFT JOIN TORDER_MST_AC AC ON AC.OWKEY = IC.OWKEY AND AC.ACKEY = IC.ACKEY AND AC.DELYN <> 'Y' LEFT JOIN TORDER_MST_ASRT ASRT ON IC.OWKEY = ASRT.OWKEY AND IC.ICKEY = ASRT.ASRTKEY LEFT JOIN TORDER_MST_IC REP ON ASRT.OWKEY = REP.OWKEY AND ASRT.ASRTREPKEY = REP.ICKEY
AND IC.DELYN = 'N'
AND IC.OWKEY = #{owkey}
AND IC.ICKEY = #{ickey}
AND IC.ASRTKEY = #{asrtkey}
AND IC.ACKEY = #{ackey}
AND IC.ICKEY = #{value}
AND ( IC.ICKEY ~ #{value} OR IC.ICNM ~ #{value} )
AND ( IC.ICKEY LIKE '%' || #{value} || '%' OR IC.ICNM LIKE '%' || #{value} || '%' )

FROM TORDER_MST_IC IC INNER JOIN TORDER_MST_ICUTXTYPE EA ON EA.OWKEY = IC.OWKEY AND EA.ICKEY = IC.ICKEY AND EA.ICUNITTYPE = IC.UOM AND EA.ICUNITTYPE = 'EA' LEFT JOIN TORDER_MST_ICUTXTYPE INN ON INN.OWKEY = IC.OWKEY AND INN.ICKEY = IC.ICKEY AND INN.ICUNITTYPE = 'INN' LEFT JOIN TORDER_MST_ICUTXTYPE CTN ON CTN.OWKEY = IC.OWKEY AND CTN.ICKEY = IC.ICKEY AND CTN.ICUNITTYPE = 'CTN' LEFT JOIN TORDER_MST_IC_ORG ORG ON IC.OWKEY = ORG.OWKEY AND IC.ICKEY = ORG.ICKEY LEFT JOIN TORDER_MST_AC AC ON AC.OWKEY = IC.OWKEY AND AC.ACKEY = IC.ACKEY AND AC.DELYN <> 'Y'
AND IC.DELYN = 'N'
AND IC.OWKEY = #{owkey}
AND IC.ICKEY = #{ickey}
AND C.ASRTKEY = #{asrtkey}
AND IC.ACKEY = #{ackey}
AND IC.ICKEY = #{value}
AND ( IC.ICKEY ~ #{value} OR IC.ICNM ~ #{value} )
AND ( IC.ICKEY LIKE '%' || #{value} || '%' OR IC.ICNM LIKE '%' || #{value} || '%' )

