FROM TORDER_MST_IC A INNER JOIN TORDER_MST_ICXCT B ON A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY INNER JOIN TORDER_MST_REQORDER C ON B.OWKEY = C.OWKEY AND B.CTKEY = C.CTKEY AND B.ICKEY = C.ICKEY WHERE C.REQORDERTYPE = '03'
