/* oms-common-sql-oracle.xml - insertTadminInfoUrHs */
INSERT INTO TADMIN_INFO_URHS (
		ACSDATE
	 ,  ACSURKEY
	 ,  ACSIP
	 ,  ACSUSKEY
	 ,  SEARCHCOND
	 ,  PRGRBIZ
	 ,  INFOTGTCNT
	 ,  INSERTDATE
	 ,  INSERTURKEY
	 ,  UPDATEDATE
	 ,  UPDATEURKEY
) VALUES (
		#{sysdate}
	 ,  #{surkey}
	 ,  #{acsip}
	 ,  #{menuId}
	 ,  #{resultParam}
	 ,  #{method}
	 ,  #{infotgtcnt}
	 ,  #{sysdate}
	 ,  #{surkey}
	 ,  #{sysdate}
	 ,  #{surkey}
)

/* oms-common-sql-oracle.xml - insertSystemNoticeFromCt */ INSERT INTO TADMIN_INFO_NOTICE ( MSGNO, MSGTYPE, STARTDT, ENDDT, TITLE, CONTENT, TARGET, PARENTMSGNO, UPPERMSGNO, HITSCNT, RIPPLECNT, OPENYN, FILEYN, FILEKEY, INSERTDATE, INSERTURKEY, UPDATEDATE, UPDATEURKEY ) SELECT (COALESCE((SELECT MAX(CAST(MSGNO AS NUMERIC)) FROM WMSON.TADMIN_INFO_NOTICE), 0) + 1)::TEXT AS MSGNO, '1', -- 시스템 알림 TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDD'), TO_CHAR(CURRENT_TIMESTAMP + #{validDays}, 'YYYYMMDD'),
'[WMS 알림] ' || CTNM || ' 운송장 사용률 임계치 도달 안내 (' || #{usert} || '%)',
CTNM || ' 운송장 사용률이 임계치(' || #{usert} || '%)에 도달하였습니다.' || CHR(10) || CHR(10) || '운송장 소진에 따른 출고 지연이 발생하지 않도록' || CHR(10) || '담당자께서는 현재 사용 현황을 확인하시고' || CHR(10) || '필요 시 추가 발급 등 사전 조치를 진행해 주시기 바랍니다.', '1', -- 전체 대상 /* PARENTMSGNO = 자기 자신 (동일 계산식) */ (COALESCE((SELECT MAX(CAST(MSGNO AS NUMERIC)) FROM WMSON.TADMIN_INFO_NOTICE), 0) + 1)::TEXT AS PARENTMSGNO, NULL, 0, 0, 'Y', 'N', NULL, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'), 'SYSTEM', TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS'), 'SYSTEM' FROM TORDER_MST_CT WHERE CTKEY = #{ctkey}
